def repeat(func):
    def wrapper():
        func()
        func()
    return wrapper

@repeat
def greet():
    print("안녕")

greet()

def shout(func):
    def wrapper(name):
        result = func(name)
        return result.upper()
    return wrapper

@shout
def greet(name):
    return f"hello {name}"

print(greet("kim"))
